const express = require('express');
const app = express();
const port = 3000;

app.use(express.json()); // Middleware to parse JSON bodies

// --- Mock User Data Store (in-memory for demonstration) ---
// In a real application, this would be a database connection.
// Passwords should be hashed using bcrypt or similar in production.
const users = [
  { id: 'user123', username: 'testuser', password: 'password123' },
  { id: 'user456', username: 'anotheruser', password: 'password456' },
];

// --- Mock Authentication Middleware ---
// This middleware simulates an authenticated user being available via req.user.
// In a real application, this would:
// 1. Read a session cookie from req.headers.cookie.
// 2. Validate the session token against a session store (e.g., Redis).
// 3. Populate req.user with the authenticated user's details.
function authMiddleware(req, res, next) {
  // For this example, we'll hardcode a logged-in user.
  // Replace this with actual session validation logic.
  const authenticatedUserId = 'user123'; // Assume 'user123' is logged in via session
  const authenticatedUser = users.find(u => u.id === authenticatedUserId);

  if (authenticatedUser) {
    req.user = { id: authenticatedUser.id, username: authenticatedUser.username }; // Attach user info to request
    next(); // Proceed to the next middleware/route handler
  } else {
    // If no authenticated user is found, send a 401 Unauthorized response.
    res.status(401).json({ message: 'Unauthorized. Please log in to perform this action.' });
  }
}

// --- Account Deletion Endpoint ---
// Requires authentication via session cookies (handled by authMiddleware)
// Expects a POST request with the user's password in the body to confirm deletion.
app.post('/delete-account', authMiddleware, (req, res) => {
  const { password } = req.body; // Extract password from the request body
  const currentUser = req.user;   // Get the authenticated user from req.user (set by authMiddleware)

  // 1. Validate request body
  if (!password) {
    return res.status(400).json({ message: 'Password is required to confirm account deletion.' });
  }

  // 2. Find the user in the mock database
  const userIndex = users.findIndex(u => u.id === currentUser.id);

  // This check is mostly for robustness; authMiddleware should ensure user exists.
  if (userIndex === -1) {
    return res.status(404).json({ message: 'Authenticated user not found in database.' });
  }

  const userToDelete = users[userIndex];

  // 3. Verify the provided password
  // In a real application, you would use bcrypt.compare(password, userToDelete.passwordHash)
  if (password !== userToDelete.password) { // Simple string comparison for demonstration
    return res.status(401).json({ message: 'Incorrect password. Account deletion failed.' });
  }

  // 4. Perform account deletion
  // In a real application, this would involve:
  //    - Deleting the user record from the database.
  //    - Invalidating all active sessions for this user (e.g., clearing their session cookie).
  //    - Potentially archiving user data instead of permanent deletion.
  users.splice(userIndex, 1); // Remove the user from our mock array

  // 5. Respond with success
  console.log(`Account for user ${currentUser.username} (ID: ${currentUser.id}) has been deleted.`);
  // In a real app, you might also clear the session cookie here:
  // res.clearCookie('session_id', { path: '/' });
  res.status(200).json({ message: 'Your account has been successfully deleted.' });
});

